mapper.sql:
SELECT A.* , CASE WHEN LCTR_WKNO_GBNCD = '04' THEN 'M' WHEN LCTR_WKNO_GBNCD = '05' THEN 'L' END AS TKEXAM_TYCD -- 주차 진행상태
, CASE WHEN TO_CHAR(SYSDATE, 'YYYYMMDD') < A.LCTR_SYMD THEN 'READY' WHEN TO_CHAR(SYSDATE, 'YYYYMMDD') BETWEEN A.LCTR_SYMD AND A.LCTR_EYMD THEN 'PROGRESS' WHEN TO_CHAR(SYSDATE, 'YYYYMMDD') > A.LCTR_EYMD THEN 'END' ELSE 'READY' END AS LESSON_SCHEDULE_PROGRESS
-- 주차 학습가능상태
, CASE WHEN TO_CHAR(SYSDATE, 'YYYYMMDD') < NVL(A.LCTR_RCG_SYMD, A.LCTR_SYMD) THEN 'READY' WHEN TO_CHAR(SYSDATE, 'YYYYMMDD') BETWEEN NVL(A.LCTR_RCG_SYMD, A.LCTR_SYMD) AND NVL(A.LCTR_RCG_EYMD, A.LCTR_EYMD) THEN 'PROGRESS' WHEN TO_CHAR(SYSDATE, 'YYYYMMDD') > NVL(A.LCTR_RCG_EYMD, A.LCTR_EYMD) THEN 'END' ELSE 'READY' END AS LESSON_SCHEDULE_STAT
-- 강의보기 가능여부 , CASE WHEN TO_CHAR(SYSDATE, 'YYYYMMDD') >= NVL(A.LCTR_RCG_SYMD, A.LCTR_SYMD) THEN 'Y' ELSE 'N' END AS START_DT_YN , CASE WHEN TO_CHAR(SYSDATE, 'YYYYMMDD') > NVL(A.LCTR_RCG_EYMD, A.LCTR_EYMD) THEN 'Y' ELSE 'N' END AS END_DT_YN , A.LCTR_NOTE_PVSNYN , (SELECT WHOL_LRN_OYN FROM TB_LMS_SBJCT WHERE SBJCT_ID = A.SBJCT_ID) AS WHOL_LRN_OYN , A.LCTR_WKNO_GBNCD , ( SELECT COUNT(1) FROM TB_LMS_SBJCT_LCTR_CONTS AA WHERE AA.LCTR_SCHDL_ID = A.LCTR_SCHDL_ID AND ( AA.LCTR_CONTS_GBNCD = 'VIDEO' OR ( AA.LCTR_CONTS_GBNCD = 'VIDEO_LINK' AND EXISTS (SELECT 1 FROM SBJCT_LCTR_CONTS_PAGE WHERE SBJCT_LCTR_CONTS_ID = AA.SBJCT_LCTR_CONTS_ID) ) ) AND AA.DELYN = 'N' AND AA.PRG_RFLTYN = 'Y' ) AS PRGR_VIDEO_CNT , ( SELECT COUNT(1) FROM TB_LMS_SBJCT_LCTR_CONTS AA WHERE AA.LCTR_SCHDL_ID = A.LCTR_SCHDL_ID AND ( AA.LCTR_CONTS_GBNCD = 'VIDEO' OR ( AA.LCTR_CONTS_GBNCD = 'VIDEO_LINK' AND EXISTS (SELECT 1 FROM SBJCT_LCTR_CONTS_PAGE WHERE SBJCT_LCTR_CONTS_ID = AA.SBJCT_LCTR_CONTS_ID) ) ) AND AA.DELYN = 'N' ) AS VIDEO_CNT , CASE WHEN EXISTS( SELECT 1 FROM TB_LMS_SBJCT_LCTR_SCHDL WHERE SBJCT_ID = A.SBJCT_ID AND DELYN = 'N' AND LCTR_SCHDL_SEQ = 14 AND TO_CHAR(SYSDATE, 'YYYYMMDD') > NVL(LCTR_RCG_EYMD, LCTR_EYMD)) THEN 'Y' ELSE 'N' END AS LESSON_SCHEDULE_END14_YN FROM TB_LMS_SBJCT_LCTR_SCHDL A JOIN TB_LMS_TERM_CRE_CRS_RLTN B ON A.SBJCT_ID = B.SBJCT_ID JOIN CRS_SMSTR C ON B.CRS_SMSTR_ID = C.CRS_SMSTR_ID WHERE A.DELYN = 'N'
AND A.SBJCT_ID IN
#{crsCreCd}
AND A.SBJCT_ID = #{crsCreCd}
AND A.LCTR_SCHDL_ID = #{lessonScheduleId}

mapper.select:
		/*
             SQL ID : LessonScheduleDAO.select
             설  명 : 강의실 학습주차 조회
         */
		SELECT
			  A.*
			, (SELECT MAX(NVL(LCTR_RCG_EYMD, LCTR_EYMD)) FROM TB_LMS_SBJCT_LCTR_SCHDL WHERE SBJCT_ID = A.SBJCT_ID AND DELYN = 'N') AS LT_DETM_TO_DT_MAX
		FROM (

			AND A.LCTR_SCHDL_ID = #{lessonScheduleId}
		) A

mapper.insert:
	/*
		 SQL ID : LessonScheduleDAO.insert
		 설  명 : 강의실 학습주차 저장
 	*/
 	INSERT INTO TB_LMS_SBJCT_LCTR_SCHDL (
 		  LCTR_SCHDL_ID
		, SBJCT_ID
		, LCTR_SCHDLNM
		, LCTR_SCHDL_SEQ
		, LCTR_GOAL
		, LCTR_OTLN
		, LCTR_REF_DATA
		, LCTR_SYMD
		, LCTR_EYMD
		, LCTR_RCG_SYMD
		, LCTR_RCG_EYMD
		, OYN
		, LCTR_TOC_LRN_SCNDS
		, LCTR_NOTE
		, LCTR_NOTE_PVSNYN
		, LCTR_WKNO_GBNCD
		, DELYN
		, RGTR_ID
		, FRST_INQ_DTTM
		, MDFR_ID
		, MOD_DTTM
 	) VALUES (
 		  #{lessonScheduleId}
		, #{crsCreCd}
		, #{lessonScheduleNm}
		, #{lessonScheduleOrder}
		, #{lessonObject}
		, #{lessonSummary}
		, #{lessonRefData}
		, #{lessonStartDt}
		, #{lessonEndDt}
		, #{ltDetmFrDt}
		, #{ltDetmToDt}
		, #{openYn}
		, #{lbnTm}
		, #{ltNote}
		, #{ltNoteOfferYn}
		, #{wekClsfGbn}
		, #{delYn}
		, #{rgtrId}
		, FN_DTTM()
		, #{mdfrId}
		, FN_DTTM()
 	)

mapper.update:
	/*
		 SQL ID : LessonScheduleDAO.update
		 설  명 : 강의실 학습주차 수정
 	*/
 	UPDATE TB_LMS_SBJCT_LCTR_SCHDL
 	SET
 		  MDFR_ID = #{mdfrId}
 		, MOD_DTTM = FN_DTTM()

 		, LCTR_TOC_LRN_SCNDS = #{lbnTmStr}


 		, LCTR_SCHDLNM = #{lessonScheduleNm}


 		, LCTR_SYMD = #{lessonStartDt}


 		, LCTR_EYMD = #{lessonEndDt}


 		, LCTR_RCG_SYMD = CASE WHEN #{ltDetmFrDt} = '' THEN NULL ELSE #{ltDetmFrDt} END


 		, LCTR_RCG_EYMD = CASE WHEN #{ltDetmToDt} = '' THEN NULL ELSE #{ltDetmToDt} END


 		, LCTR_NOTE_PVSNYN = #{ltNoteOfferYn}


 		, LCTR_NOTE = CASE WHEN #{ltNote} = '' THEN NULL ELSE #{ltNote} END


 		, OYN = #{openYn}


 		, LCTR_WKNO_GBNCD = #{wekClsfGbn}

 	WHERE LCTR_SCHDL_ID = #{lessonScheduleId}

	/*
		 SQL ID : LessonScheduleDAO.updateDelN
		 설  명 : 강의실 학습주차 삭제
 	*/
 	UPDATE TB_LMS_SBJCT_LCTR_SCHDL
 	SET
 		  MDFR_ID = #{mdfrId}
 		, MOD_DTTM = FN_DTTM()
 		, DELYN = 'Y'
 	WHERE LCTR_SCHDL_ID = #{lessonScheduleId}

mapper.sql:
SELECT
A.LCTR_SCHDL_ID , A.LCTR_SCHDLNM , A.LCTR_SCHDL_SEQ , A.LCTR_OTLN , A.LCTR_SYMD , A.LCTR_EYMD , A.LCTR_RCG_SYMD , A.LCTR_RCG_EYMD , A.LCTR_TOC_LRN_SCNDS , A.LCTR_NOTE , A.LCTR_NOTE_PVSNYN , A.LESSON_SCHEDULE_PROGRESS , A.LESSON_SCHEDULE_STAT , A.OYN , A.TKEXAM_TYCD , A.START_DT_YN , A.END_DT_YN , A.SBJCT_ID , A.WHOL_LRN_OYN , A.LCTR_WKNO_GBNCD , A.PRGR_VIDEO_CNT , A.LESSON_SCHEDULE_END14_YN -- 주차 > 교시 , B.SBJCT_LCTR_CLASTM_ID , B.LCTR_CLASTMNM , B.LCTR_CLASTM_SEQ , B.LCTR_MTHD -- 주차 > 교시 > 학습콘텐츠 , C.SBJCT_LCTR_CONTS_ID , C.LCTR_CONTS_GBNCD , C.LCTR_CONTSNM , C.LCTR_CONTS_SEQ , C.LCTR_SDTTM , C.LCTR_EDTTM , C.PRG_RFLTYN , C.LESSON_CNTS_URL -- 주차 > 교시 > 학습콘텐츠 > 학습페이지 , D.SBJCT_LCTR_CONTS_ID AS PAGE_LESSON_CNTS_ID , D.PAGE_SEQNO , D.ULD_GBNCD , D.PAGENM , D.URL -- 주차 > 교시 > 세미나 , E.SMNR_ID , E.SEMINAR_NM , E.SMNR_SDTTM , E.SMNR_EDTTM , E.SMNR_CTGRCD , E.SMNR_MNTS FROM (
) A LEFT JOIN TB_LMS_SBJCT_LCTR_CLASTM B ON A.LCTR_SCHDL_ID = B.LCTR_SCHDL_ID LEFT JOIN TB_LMS_SBJCT_LCTR_CONTS C ON B.SBJCT_LCTR_CLASTM_ID = C.SBJCT_LCTR_CLASTM_ID AND C.DELYN = 'N' AND ( C.LCTR_CONTS_GBNCD != 'VIDEO_LINK' OR ( -- SBJCT_LCTR_CONTS_PAGE 값이 있어야 조회 C.LCTR_CONTS_GBNCD = 'VIDEO_LINK'
AND EXISTS(SELECT 1 FROM SBJCT_LCTR_CONTS_PAGE WHERE SBJCT_LCTR_CONTS_ID = C.SBJCT_LCTR_CONTS_ID)
) ) LEFT JOIN SBJCT_LCTR_CONTS_PAGE D ON C.SBJCT_LCTR_CONTS_ID = D.SBJCT_LCTR_CONTS_ID LEFT JOIN TB_LMS_SMNR E ON B.SBJCT_LCTR_CLASTM_ID = E.SBJCT_LCTR_CLASTM_ID AND E.DELYN = 'N'

mapper.select:
/* SQL ID : LessonScheduleDAO.listLessonScheduleByGbn 설 명 : 강의구분별 주차 목록 조회 */ SELECT LCTR_SCHDL_ID , LCTR_SCHDLNM , LCTR_SCHDL_SEQ FROM TB_LMS_SBJCT_LCTR_SCHDL WHERE SBJCT_ID = #{crsCreCd} AND DELYN = 'N'
AND LCTR_WKNO_GBNCD IN ('02', '03')
AND LCTR_WKNO_GBNCD = #{wekClsfGbn}
AND LCTR_WKNO_GBNCD NOT IN ('02', '03')
ORDER BY LCTR_SCHDL_SEQ

mapper.insert:
		/*
			 SQL ID : LessonScheduleDAO.insertLessonScheduleListForTrans
			 설  명 : 주차 목록 저장(선수강과목 이관용)
	 	*/
	 	INSERT IGNORE INTO TB_LMS_SBJCT_LCTR_SCHDL (
	 		  LCTR_SCHDL_ID
			, SBJCT_ID
			, LCTR_SCHDLNM
			, LCTR_SCHDL_SEQ
			, LCTR_GOAL
			, LCTR_OTLN
			, LCTR_REF_DATA
			, LCTR_SYMD
			, LCTR_EYMD
			, LCTR_RCG_SYMD
			, LCTR_RCG_EYMD
			, OYN
			, LCTR_TOC_LRN_SCNDS
			, LCTR_NOTE
			, LCTR_NOTE_PVSNYN
			, LCTR_WKNO_GBNCD
			, DELYN
			, RGTR_ID
			, FRST_INQ_DTTM
			, MDFR_ID
			, MOD_DTTM
	 	) VALUES

        (
	 		  #{item.lessonScheduleId}
			, #{item.crsCreCd}
			, #{item.lessonScheduleNm}
			, #{item.lessonScheduleOrder}
			, #{item.lessonObject}
			, #{item.lessonSummary}
			, #{item.lessonRefData}
			, #{item.lessonStartDt}
			, #{item.lessonEndDt}
			, #{item.ltDetmFrDt}
			, #{item.ltDetmToDt}
			, #{item.openYn}
			, #{item.lbnTm}
			, #{item.ltNote}
			, #{item.ltNoteOfferYn}
			, #{item.wekClsfGbn}
			, #{item.delYn}
			, #{item.rgtrId}
            , #{item.regDttm}
            , #{item.mdfrId}
            , #{item.modDttm}
	 	)

mapper.select:
/* SQL ID : LessonScheduleDAO.listDeclsLessonSchedule 설 명 : 분반 주차 조회 */ SELECT A.SBJCT_ID , A.LCTR_SCHDL_ID , A.LCTR_SCHDL_SEQ FROM TB_LMS_SBJCT_LCTR_SCHDL A WHERE A.DELYN = 'N' AND A.SBJCT_ID IN
#{crsCreCd}
AND LCTR_SCHDL_SEQ = ( SELECT LCTR_SCHDL_SEQ FROM TB_LMS_SBJCT_LCTR_SCHDL A WHERE A.DELYN = 'N' AND A.LCTR_SCHDL_ID = #{lessonScheduleId} )
